/**
 * Path-based router for the Motivation PWA.
 * Leans heavily on the Navigation API (supported on all target devices).
 */

export interface RouteContext {
    path: string;
    params: Record<string, string>;
    query: URLSearchParams;
}

export interface RouteConfig {
    render: (ctx: RouteContext) => HTMLElement | Promise<HTMLElement>;
}

// ── Navigation helpers ──────────────────────────────────────────────────────

/**
 * Attach a rejection handler to BOTH promises of a NavigationResult.
 *
 * The Navigation API returns two promises (`committed` and `finished`) and
 * either can reject independently — e.g. after a long PWA suspension Chrome
 * may discard the underlying session-history entry, in which case `back()` /
 * `traverseTo()` reject both with `InvalidStateError: Invalid key`. Catching
 * only `finished` leaves `committed`'s rejection to surface as an unhandled
 * promise rejection.
 *
 * `onFail` runs at most once. Aborts (e.g. a competing navigation) are
 * ignored — they're a normal part of the API contract, not user-facing errors.
 */
function handleNavigationResult(
    result: { committed?: Promise<unknown>; finished?: Promise<unknown> },
    onFail: (err: unknown) => void,
): void {
    let handled = false;
    const handler = (err: unknown) => {
        if (handled) return;
        if (err instanceof DOMException && err.name === 'AbortError') return;
        handled = true;
        onFail(err);
    };
    result.committed?.catch(handler);
    result.finished?.catch(handler);
}

export function navigate(path: string, options?: { history?: 'push' | 'replace' }): void {
    const url = path.startsWith('/') ? path : `/${path}`;
    const result = window.navigation.navigate(url, options?.history ? { history: options.history } : undefined);
    handleNavigationResult(result, (err) => {
        console.warn('[ROUTER] navigation failed', url, err);
    });
}

export function goBack(fallbackPath = '/'): void {
    let result: { committed?: Promise<unknown>; finished?: Promise<unknown> };
    try {
        result = window.navigation.back();
    } catch {
        // `back()` throws synchronously when there is no previous entry, or
        // when the previous entry's key is no longer valid.
        navigate(fallbackPath, { history: 'replace' });
        return;
    }

    handleNavigationResult(result, () => {
        navigate(fallbackPath, { history: 'replace' });
    });
}

/**
 * Jump back in history past a multi-step flow to the first entry whose path is
 * not a flow step. `flowPrefixes` matches a path if it equals the prefix or
 * starts with `prefix + '/'`. If no such entry exists (cold-start reload, etc.)
 * we navigate to `fallbackPath` with replace.
 */
export async function popOutOfFlow(flowPrefixes: string[], fallbackPath: string): Promise<void> {
    const entries = window.navigation.entries();
    const currentIdx = window.navigation.currentEntry?.index ?? -1;

    for (let i = currentIdx - 1; i >= 0; i--) {
        const entry = entries[i];
        if (!entry?.url) continue;
        const path = new URL(entry.url).pathname;
        const isFlow = flowPrefixes.some((p) => path === p || path.startsWith(`${p}/`));
        if (isFlow) continue;
        try {
            const result = window.navigation.traverseTo(entry.key);
            // Attach a catch to `committed` too so a stale-key rejection
            // doesn't escape as an unhandled rejection while we're awaiting
            // `finished`.
            result.committed?.catch(() => {});
            await result.finished;
            return;
        } catch {
            break;
        }
    }

    navigate(fallbackPath, { history: 'replace' });
}

// ── Router ──────────────────────────────────────────────────────────────────

export function startRouter(
    routes: Record<string, RouteConfig>,
    target: HTMLElement,
): () => void {
    let currentRoute = '';
    let currentFullPath = '';
    let renderSequence = 0;
    let pendingStaleCleanup: (() => void) | null = null;

    async function activate(url: URL): Promise<void> {
        if (pendingStaleCleanup) {
            pendingStaleCleanup();
            pendingStaleCleanup = null;
        }

        const path = normalizePath(url.pathname);
        const query = new URLSearchParams(url.search);
        const { route, params } = matchRoute(path, routes);

        if (route === '/' && path !== '/') {
            navigate('/', { history: 'replace' });
            return;
        }

        const fullPath = `${path}${query.toString() ? `?${query}` : ''}`;
        if (fullPath === currentFullPath) return;

        const isBack = isBackNavigation(currentRoute, route);
        currentRoute = route;
        currentFullPath = fullPath;

        if (isBack) {
            document.documentElement.classList.add('back-transition');
        } else {
            document.documentElement.classList.remove('back-transition');
        }

        const config = routes[route];
        if (!config) return;

        const activationId = ++renderSequence;
        const render = async () => {
            let screen: HTMLElement;
            try {
                screen = await config.render({ path, params, query });
                try {
                    sessionStorage.removeItem('stale_bundle_reloaded');
                } catch {
                    // Ignore storage errors
                }
            } catch (err) {
                if (looksLikeStaleBundle(err)) {
                    let alreadyReloaded = false;
                    try {
                        alreadyReloaded = sessionStorage.getItem('stale_bundle_reloaded') === 'true';
                    } catch {
                        // ignore
                    }

                    let reloadTimeout: ReturnType<typeof setTimeout> | null = null;
                    let countdownInterval: ReturnType<typeof setInterval> | null = null;

                    const cancelReload = () => {
                        if (reloadTimeout) clearTimeout(reloadTimeout);
                        if (countdownInterval) clearInterval(countdownInterval);
                    };

                    screen = buildStaleBundleScreen(path, {
                        alreadyReloaded,
                        onCancel: cancelReload
                    });

                    pendingStaleCleanup = cancelReload;

                    if (!alreadyReloaded) {
                        let secondsLeft = 5;
                        reloadTimeout = setTimeout(() => {
                            if (countdownInterval) clearInterval(countdownInterval);
                            try {
                                sessionStorage.setItem('stale_bundle_reloaded', 'true');
                            } catch {
                                // ignore
                            }
                            window.location.reload();
                        }, 5000);

                        const textEl = screen.querySelector('.stale-bundle__countdown-text');
                        if (textEl) {
                            countdownInterval = setInterval(() => {
                                secondsLeft--;
                                if (secondsLeft > 0) {
                                    textEl.textContent = `Refreshing automatically in ${secondsLeft} seconds... `;
                                } else {
                                    textEl.textContent = 'Refreshing...';
                                    if (countdownInterval) clearInterval(countdownInterval);
                                }
                            }, 1000);
                        }
                    }
                } else {
                    screen = buildRouteErrorScreen(path, err);
                }
            }
            if (activationId === renderSequence) {
                target.replaceChildren(screen);
            }
        };

        if (document.startViewTransition && document.visibilityState === 'visible') {
            try {
                await document.startViewTransition(render).finished;
            } catch {
                await render();
            }
        } else {
            await render();
        }
    }

    const onNavigate = (event: NavigateEvent) => {
        if (!event.canIntercept) return;
        const destination = new URL(event.destination.url);
        if (destination.origin !== window.location.origin) return;

        event.intercept({
            scroll: 'manual',
            async handler() {
                await activate(destination);
                event.scroll();
            },
        });
    };

    window.navigation.addEventListener('navigate', onNavigate);
    void activate(new URL(window.location.href));

    return () => {
        if (pendingStaleCleanup) {
            pendingStaleCleanup();
        }
        window.navigation.removeEventListener('navigate', onNavigate);
    };
}

function buildRouteErrorScreen(path: string, err: unknown): HTMLElement {
    const message = err instanceof Error ? (err.stack ?? `${err.name}: ${err.message}`) : String(err);
    const el = document.createElement('section');
    el.className = 'route-error';
    el.dataset.path = path;

    const heading = document.createElement('h2');
    heading.textContent = `Failed to load ${path}`;
    el.appendChild(heading);

    const hint = document.createElement('p');
    hint.textContent = 'The route handler threw an error. Common cause: a dynamic import chunk is not cached and the network is offline.';
    el.appendChild(hint);

    const pre = document.createElement('pre');
    pre.className = 'route-error__stack';
    pre.textContent = message;
    el.appendChild(pre);

    const reload = document.createElement('button');
    reload.type = 'button';
    reload.textContent = 'Reload';
    reload.addEventListener('click', () => { window.location.reload(); });
    el.appendChild(reload);

    return el;
}

const STALE_BUNDLE_PATTERNS = [
    /Failed to fetch dynamically imported module/i, // Chrome
    /error loading dynamically imported module/i,   // Safari
    /Importing a module script failed/i,            // Firefox
];

function looksLikeStaleBundle(err: unknown): boolean {
    const msg = err instanceof Error ? err.message : String(err);
    return STALE_BUNDLE_PATTERNS.some((re) => re.test(msg));
}

function buildStaleBundleScreen(
    path: string, 
    options: { 
        alreadyReloaded: boolean; 
        onCancel: () => void; 
    }
): HTMLElement {
    const el = document.createElement('section');
    el.className = 'route-error stale-bundle';
    el.dataset.path = path;

    const heading = document.createElement('h2');
    heading.textContent = 'App updated — refresh to load the new version';
    el.appendChild(heading);

    const hint = document.createElement('p');
    hint.textContent = 'The application has been updated on the server. The section you requested needs the latest version of the app to load.';
    el.appendChild(hint);

    const countdownContainer = document.createElement('div');
    countdownContainer.className = 'stale-bundle__countdown-container';
    
    if (!options.alreadyReloaded) {
        const countdownText = document.createElement('span');
        countdownText.className = 'stale-bundle__countdown-text';
        countdownText.textContent = 'Refreshing automatically in 5 seconds... ';
        countdownContainer.appendChild(countdownText);

        const cancelBtn = document.createElement('button');
        cancelBtn.type = 'button';
        cancelBtn.className = 'stale-bundle__cancel';
        cancelBtn.textContent = 'Cancel';
        cancelBtn.addEventListener('click', () => {
            options.onCancel();
            countdownContainer.textContent = 'Auto-refresh cancelled.';
        });
        countdownContainer.appendChild(cancelBtn);
    } else {
        const warning = document.createElement('p');
        warning.className = 'stale-bundle__warning';
        warning.textContent = 'Note: We already tried to refresh automatically. If the issue persists, please check your network connection or try reloading manually.';
        countdownContainer.appendChild(warning);
    }
    
    el.appendChild(countdownContainer);

    const actions = document.createElement('div');
    actions.className = 'stale-bundle__actions';
    
    const refreshBtn = document.createElement('button');
    refreshBtn.type = 'button';
    refreshBtn.className = 'stale-bundle__refresh';
    refreshBtn.textContent = 'Refresh now';
    refreshBtn.addEventListener('click', () => {
        try {
            sessionStorage.setItem('stale_bundle_reloaded', 'true');
        } catch {
            // ignore
        }
        window.location.reload();
    });
    actions.appendChild(refreshBtn);
    
    el.appendChild(actions);

    return el;
}

// ── Internals ───────────────────────────────────────────────────────────────

export function matchRoute(
    pathname: string,
    routes: Record<string, RouteConfig>,
): { route: string; params: Record<string, string> } {
    const path = normalizePath(pathname);

    if (path === '/') return { route: '/', params: {} };
    if (routes[path]) return { route: path, params: {} };

    for (const pattern of Object.keys(routes)) {
        if (!pattern.includes(':')) continue;

        const patternParts = pattern.split('/');
        const pathParts = path.split('/');
        if (patternParts.length !== pathParts.length) continue;

        const params: Record<string, string> = {};
        let match = true;

        for (let i = 0; i < patternParts.length; i++) {
            if (patternParts[i].startsWith(':')) {
                if (!pathParts[i]) { match = false; break; }
                params[patternParts[i].substring(1)] = pathParts[i];
            } else if (patternParts[i] !== pathParts[i]) {
                match = false;
                break;
            }
        }

        if (match) return { route: pattern, params };
    }

    return { route: '/', params: {} };
}

function isBackNavigation(fromRoute: string, toRoute: string): boolean {
    if (!fromRoute) return false;
    if (toRoute === '/' && fromRoute !== '/') return true;
    return fromRoute.startsWith(toRoute + '/');
}

function normalizePath(path: string): string {
    if (!path || path === '/') return '/';
    const p = path.startsWith('/') ? path : `/${path}`;
    return p.endsWith('/') ? p.slice(0, -1) : p;
}
